package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidAppendable() throws IOException, NoSuchFieldException, IllegalAccessException {
        Appendable appendable = mock(Appendable.class);
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);

        // Use reflection to access the private 'out' field of CSVPrinter
        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        Object out = outField.get(printer);

        // The printer should use the given appendable
        assertSame(appendable, out);
    }

    @Test
    void testPrintWithAppendableThatThrowsIOException() {
        Appendable appendable = mock(Appendable.class);
        try {
            // Force an IOException by mocking CSVPrinter constructor indirectly is complicated,
            // so here we just check that print does not throw IOException itself.
            CSVPrinter printer = csvFormat.print(appendable);
            assertNotNull(printer);
        } catch (IOException e) {
            fail("print should not throw IOException when passed a valid Appendable");
        }
    }
}
